module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);
parameter N = 8;
parameter _2N = 16;
reg [1:0] mul_en_out_reg;
assign mul_en_out = mul_en_out_reg[N-1];
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        mul_en_out_reg <= 2'd0;
    else
        mul_en_out_reg <= {mul_en_out_reg[N-2:0], mul_en_in};
end
reg [N-1:0] mul_a_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        mul_a_reg <= 8'd0;
    else if (mul_en_in)
        mul_a_reg <= mul_a;
end
reg [N-1:0] mul_b_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        mul_b_reg <= 8'd0;
    else if (mul_en_in)
        mul_b_reg <= mul_b;
end
wire [N-1:0] temp[0:N-1];
genvar i;
generate
    for (i = 0; i < N; i = i + 1) begin : gen_loop
        assign temp[i] = mul_a_reg[i] && mul_b_reg[N-1-i];
    end
endgenerate
reg [2*N-1:0] sum;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        sum[0] <= 1'b0;
    else
        sum[0] <= temp[0];
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        for (i = 1; i < N; i = i + 1) begin : add_loop
            sum[i] <= 1'b0;
        end
    else
        for (i = 1; i < N; i = i + 1) begin : add_loop
            sum[i] <= temp[i] + sum[i-1];
        end
end
reg [2*N-1:0] mul_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        mul_out_reg <= 16'd0;
    else
        mul_out_reg <= sum;
end
assign mul_out = mul_en_out ? mul_out_reg : 16'd0;
endmodule
